draw((1,0)--(2,1)--(2,2));
dot((1,0));
label("$C$",(1,0),SE);
dot((0,0));
label("$D$",(0,0),SW);
dot((0,1));
label("$A$",(0,1),W);
dot((2,1));
label("$B$",(2,1),E);
[/asy]

